function onSave()
    local data_to_save = {
        twStarted=hasGameStarted,
        twPlayers=numPlayers,
        twMages=mages,
        twAdventurePack=adventurePack,
        twSkellige=skellige,
        twLegendaryHunt=legendaryHunt,
        twUniqueActions=uniqueActions,
        twBombs=bombs,
        twAdvancedActions=advancedActions,
        twMonsterWeakness=monsterWeakness,
        twMutagens=mutagens,
        twWildHunt=wildHunt,
        twWHDifficulty=whDifficulty,
        twWHBoss=whBoss,
        twLostMount=lostMount,
        twSiren=siren,
        twTroll=troll,
        twKoshchey=koshchey,
        twKayran=kayran,
        twAutoma=automa,
        twMountedEredinLegendary=mountedEredinLegendary,
        };
    saved_data = JSON.encode(data_to_save);
    return saved_data;
end

--Runs when game is loaded.
function onLoad(saved_data)
    --Loads the tracking for if the game has started yet
    if saved_data ~= "" then
        local loaded_data = JSON.decode(saved_data)
        hasGameStarted = loaded_data.twStarted
        numPlayers = loaded_data.twPlayers
        mages = loaded_data.twMages
        adventurePack = loaded_data.twAdventurePack
        skellige = loaded_data.twSkellige
        legendaryHunt = loaded_data.twLegendaryHunt
        uniqueActions = loaded_data.twUniqueActions
        bombs = loaded_data.twBombs
        advancedActions = loaded_data.twAdvancedActions
        monsterWeakness = loaded_data.twMonsterWeakness
        mutagens = loaded_data.twMutagens
        wildHunt = loaded_data.twWildHunt
        whDifficulty = loaded_data.twWHDifficulty
        whBoss = loaded_data.twWHBoss
        lostMount = loaded_data.twLostMount
        siren = loaded_data.twSiren
        troll = loaded_data.twTroll
        koshchey = loaded_data.twKoshchey
        kayran = loaded_data.twKayran
        automa = loaded_data.twAutoma
        mountedEredinLegendary = loaded_data.twMountedEredinLegendary
        marketInProgress = false
        currentlySpawning = false
    end

    if hasGameStarted then
        self.UI.setAttribute( "setupTool", "active", "false" );
        createMarketButtons()
    else
        numPlayers = 2;
        marketInProgress = false;
        mages = true;
        adventurePack = true;
        skellige = false;
        legendaryHunt = false;
        uniqueActions = true;
        bombs = true;
        advancedActions = true;
        monsterWeakness = true;
        mutagens = true;
        wildHunt = false;
        whDifficulty = "Normal";
        whBoss = "Nithral";
        lostMount = false;
        siren = false;
        troll = true;
        koshchey = true;
        kayran = false;
        automa = false;
        mountedEredinLegendary = false;
        currentlySpawning = false;
        UI.show("setupTool")
        printToAll( "Elige las expansiones que quieras incluir y pulsa sobre Start Game.", {0.0, 1.0, 0.5, 1} );
    end
end



