function increase_trophy(button, color, _)
    local scoreToken = nil
    for i, obj in ipairs(getAllObjects()) do
        if obj.hasTag("ScoringToken") and obj.hasTag(color) then
            scoreToken = obj
        end
    end

    if scoreToken ~= nil then
        local scoreTokenPos = scoreToken.getPosition()

        if scoreTokenPos.z > 1 then
            scoreToken.setPositionSmooth({5.24,2,0.45})
        elseif scoreTokenPos.z > 0 and scoreTokenPos.z < 1 then
            scoreToken.setPositionSmooth({5.24,2,-0.44})
        elseif scoreTokenPos.z > -1 and scoreTokenPos.z < 0 then
            scoreToken.setPositionSmooth({5.24,2,-1.33})
        elseif scoreTokenPos.z > -2 and scoreTokenPos.z < -1 then
            scoreToken.setPositionSmooth({5.24,2,-2.22})
        end
    end
end

function decrease_trophy(button, color, _)
    local scoreToken = nil
    for i, obj in ipairs(getAllObjects()) do
        if obj.hasTag("ScoringToken") and obj.hasTag(color) then
            scoreToken = obj
        end
    end

    if scoreToken ~= nil then
        local scoreTokenPos = scoreToken.getPosition()

        if scoreTokenPos.z < -2 then
            scoreToken.setPositionSmooth({5.24,2,-1.33})
        elseif scoreTokenPos.z > -2 and scoreTokenPos.z < -1 then
            scoreToken.setPositionSmooth({5.24,2,-0.44})
        elseif scoreTokenPos.z > -1 and scoreTokenPos.z < 0 then
            scoreToken.setPositionSmooth({5.24,2,0.45})
        elseif scoreTokenPos.z > 0 and scoreTokenPos.z < 1 then
            scoreToken.setPositionSmooth({5.24,2,1.36})
        end
    end
end

