function spawn_monster(button, level)
    local monsterDeck = nil
    local monsterTrophyDeck = nil
    local locationBag = nil
    local locationPos = nil
    local monsterTokenPos = nil
    local monsterCardPos = nil
    local locationWeaknessPos = nil
    local locationType = ""
    local existingLocation = nil
    local existingWeaknessLocation = nil
    local existingMonster = nil
    local monsterToken = nil
    local tokenBag = nil
    local I_level = nil
    if currentlySpawning then
        return
    end
    currentlySpawning = true
    Wait.time(function() currentlySpawning = false end, 1)

    if not monsterWeakness then
        if level == 1 then
            monsterDeck = GetDeckOnPosition( PosLevel1Pile )
            tokenBag = getObjectFromGUID( level1MonsterTokensGUID )
            I_level = "I"
        elseif level == 2 then
            monsterDeck = GetDeckOnPosition( PosLevel2Pile )
            tokenBag = getObjectFromGUID( level2MonsterTokensGUID )
            I_level = "II"
        elseif level == 3 then
            monsterDeck = GetDeckOnPosition( PosLevel3Pile )
            tokenBag = getObjectFromGUID( level3MonsterTokensGUID )
            I_level = "III"
        end
    elseif monsterWeakness then
        if level == 1 then
            monsterTrophyDeck = GetDeckOnPosition( PosLevel1Pile )
            monsterDeck = GetDeckOnPosition( PosLargeLevel1Pile )
            tokenBag = getObjectFromGUID( level1MonsterTokensGUID )
            I_level = "I"
        elseif level == 2 then
            monsterTrophyDeck = GetDeckOnPosition( PosLevel2Pile )
            monsterDeck = GetDeckOnPosition( PosLargeLevel2Pile )
            tokenBag = getObjectFromGUID( level2MonsterTokensGUID )
            I_level = "II"
        elseif level == 3 then
            monsterTrophyDeck = GetDeckOnPosition( PosLevel3Pile )
            monsterDeck = GetDeckOnPosition( PosLargeLevel3Pile )
            tokenBag = getObjectFromGUID( level3MonsterTokensGUID )
            I_level = "III"
        end
    end

    if button == monster_1_forest or button == monster_2_forest or button == monster_3_forest then
        locationType = "Forest"
        locationBag = getObjectFromGUID( forestLocationsGUID )
        locationPos = PosForestLocation
        monsterTokenPos = PosForestMonsterToken
        monsterCardPos = PosForestMonsterCard
        locationWeaknessPos = PosForestWeaknessLocation
    elseif button == monster_1_water or button == monster_2_water or button == monster_3_water then
        locationType = "Water"
        locationBag = getObjectFromGUID( waterLocationsGUID )
        locationPos = PosWaterLocation
        monsterTokenPos = PosWaterMonsterToken
        monsterCardPos = PosWaterMonsterCard
        locationWeaknessPos = PosWaterWeaknessLocation
    elseif button == monster_1_mountain or button == monster_2_mountain or button == monster_3_mountain then
        locationType = "Mountain"
        locationBag = getObjectFromGUID( mountainLocationsGUID )
        locationPos = PosMountainLocation
        monsterTokenPos = PosMountainMonsterToken
        monsterCardPos = PosMountainMonsterCard
        locationWeaknessPos = PosMountainWeaknessLocation
    end

    existingMonster = GetDeckOnPosition( monsterCardPos )
    if existingMonster ~= nil then
        broadcastToAll("No puede aparecer un nuevo monstruo, ya hay uno aquí.",{1,.5,.5})
        if not monsterWeakness then
            printToAll("Recoge el trofeo de monstruo antes de hacer aparecer un nuevo monstruo.",{1,1,1})
            printToAll("(o elimina la carta de monstruo si fue expulsado).",{.8,.8,.8})
            return
        elseif monsterWeakness then
            printToAll("Por favor elimina la carta grande del monstruo antes de hacer aparecer un nuevo monstruo.",{1,1,1})
            printToAll("(si este monstruo fue derrotado, asegurate de recoger el trofeo correspondiente del mazo pequeño de monstruos)",{.8,.8,.8})
            return
        end
    end

    existingLocation = GetLocOnPosition( locationPos )
    if existingLocation ~= nil then
        locationBag.putObject( existingLocation )
    end
    existingWeaknessLocation = GetLocOnPosition( locationWeaknessPos )
    if existingWeaknessLocation ~= nil then
        locationBag.putObject( existingWeaknessLocation )
    end

    if monsterDeck ~= nil then
        if monsterDeck.tag == "Deck" then
            monsterDeck.shuffle()
        end
        Wait.time(
            function()
                if monsterDeck.tag == "Deck" then
                    local newMonster = monsterDeck.takeObject({position = monsterCardPos, rotation = {0,0,0}})
                    monsterName = newMonster.getName()
                elseif monsterDeck.tag == "Card" then
                    local newMonster = monsterDeck
                    newMonster.setPositionSmooth(monsterCardPos)
                    monsterName = newMonster.getName()
                end
                local newLocation = locationBag.takeObject({position = locationPos, rotation = {0,0,0}})
                broadcastToAll("Generando un monstruo de nivel "..I_level..", Monstruo: "..monsterName,{.14,.7,1})
                printToAll("en el Lugar "..newLocation.getGMNotes(),{1,1,1})

                for i, obj in ipairs( tokenBag.getObjects() ) do
                    if obj.name == monsterName then
                        item = obj;
                    end
                end

                if item ~= nil then
                    tokenBag.takeObject({
                        guid = item.guid,
                        position = monsterTokenPos,
                        rotation = {0,0,0},
                    });
                end

                if monsterWeakness then
                    for i, obj in ipairs( monsterTrophyDeck.getObjects() ) do
                        if obj.name == monsterName then
                            item = obj;
                        end
                    end
                    if item ~= nil then
                        monsterTrophyDeck.takeObject({
                            guid = item.guid,
                            position = VectorAdd(monsterTrophyDeck.getPosition(), {0,2,0}),
                            rotation = {0,0,0},
                        });
                    end
                    local newWeaknessLocation = locationBag.takeObject({position = locationWeaknessPos, rotation = {0,0,0}})
                    printToAll("Roba una ficha de Debilidad bocaabajo de "..locationType.." y colocala en el tablero",{1,.7,.7})
                    printToAll("en el Lugar "..newWeaknessLocation.getGMNotes(),{1,1,1})
                    printToAll("A continuación, devuelvo ese lugar a la bolsa",{1,.7,.7})
                    --printToAll("(if there's a Witcher or Mage already at Location "..newWeaknessLocation.getGMNotes()..", manually draw a new location to place the Weakness token.)",{.8,.8,.8})
                end
            end
        ,0.1);
    else
        broadcastToAll("No quedan monstruos de Nivel "..I_level..".",{1,1,1})
        return
    end
end



