function GetDeckOnPosition( pos )
    local found = Physics.cast({
        origin = pos,
        direction = {0,1,0},
        type = 3,
        size = { 0.5, 3.0, 0.5 },
        max_distance = 0
    });

    local numCards = 0;
    local firstCard = nil;

    for key, val in ipairs( found ) do
        if val.hit_object.tag == "Deck" then
            return val.hit_object;
        elseif val.hit_object.tag == "Card" then
            if numCards == 0 then
                firstCard = val.hit_object;
            end

            numCards = numCards + 1;
        end

        if numCards == 1 then
            return firstCard;
        end
    end

    return nil;
end

function GetLocOnPosition( pos )
    local found = Physics.cast({
        origin = pos,
        direction = {0,1,0},
        type = 3,
        size = { 0.5, 3.0, 0.5 },
        max_distance = 0
    });

    local numCards = 0;
    local firstCard = nil;

    for key, val in ipairs( found ) do
        if val.hit_object.hasTag("Location") then
            return val.hit_object;
        end
    end

    return nil;
end

