function DrawCards(deckGUID, numCards, position, flip, isSmooth)
    if flip == nil then
        flip = false;
    end
    local rotation = {0.00, 0.00, 180.00};
    if flip == true then
        rotation = {0.00, 0.00, 0.00};
    end

    if isSmooth == nil then
        isSmooth = false;
    end

    local deck = getObjectFromGUID(deckGUID)
    if deck == nil then
        print("¡No se ha encontrado el mazo!")
        return
    end

    for i = 1, numCards do
        local card = deck.takeObject({
            position = position,
            rotation = rotation,
            smooth = isSmooth,
            index = 1
        })
        if card == nil then
            print("¡No se ha podido robar una carta!")
            return
        end
    end
end

function ActionSetup()
    local actionDeck = GetDeckOnPosition( PosActionPile );
    local card = nil;
    printToAll("Preparando el Mercado",{.2,.6,1});
    actionDeck.shuffle();
    for i = 1, 6 do
        card = actionDeck.takeObject({
            position = PosAction[i],
            flip = true,
            smooth = false,
        })
        if card == nil then
            print("¡No se ha podido robar una carta de Acción!")
            return
        end

        if i < 4 then
            while card.getDescription() ~= "0" do
                local x = 1;
                card.setPosition( VectorAdd(PosActionDiscard,{0,x * 1, 0}));
                x = x + 1;
                card = actionDeck.takeObject({
                    position = PosAction[i],
                    flip = true,
                    smooth = false,
                })
            end
        end
    end

    Wait.time(
        function()
