function VectorAdd( v1, v2 )
    return {v1[1] + v2[1], v1[2] + v2[2], v1[3] + v2[3]};
end

function SetupExtractBagFromBox( box, bagName, placeAtPosition, bagPosition, bagRotation, flip )
    if box.getQuantity() <= 0 then
        return false;
    end

    local contents = box.getObjects();

    for key, val in ipairs( contents ) do
        if val.name == bagName then
            box.takeObject({
                index = key - 1,
                position = bagPosition,
                rotation = bagRotation,
                smooth = false,
                callback_function = function( a )
                    if a.tag == "Deck" or a.tag == "Card" or a.hasTag == "Token" then
                        local rotation = {0.00, 0, 180.00};

                        if flip == false then
                            rotation = {0.00, 0, 0.00};
                        end

                        a.setRotation( rotation );
                        a.setPosition( placeAtPosition );
                    else
                        SetupExtractDeckFromBag( a, placeAtPosition, flip );

                        if a.getStateId() ~= 2 then
                            a.setState( 2 );
                        end
                    end
                end
            });
        end
    end
end

function SetupExtractDeckFromBag( bag, placeAtPosition, flip )
    if bag.getQuantity() ~= 1 then
        return false;
    end

    local rotation = {0.00, 0.00, 180.00};

    if flip == false then
        rotation = {0.00, 0.00, 0.00};
    end

    bag.takeObject({
        index = 0,
        position = placeAtPosition,
        rotation = rotation,
        smooth = false
    });

    return true;
end

function SetupAddByGUID(boxName, itemGUID, placeAtPosition, flip)
    if flip == nil then
        flip = true;
    end
    local box = nil;
    local allObjects = getAllObjects();

    for key, val in ipairs( allObjects ) do
        if val.tag == "Bag" then
            if val.getName() == boxName then
                box = val;
            end
        end
    end

    local rotation = {0.00, 0.00, 0.00};

    if flip == false then
        rotation = {0.00, 0.00, 180.00};
    end

    box.takeObject({
        guid = itemGUID,
        position = placeAtPosition,
        rotation = rotation,
        smooth = false
        });
end

function SetupAddByNote( boxName, itemName, gmCheck, placeAtPosition, flip)
    if flip == nil then
        flip = true;
    end
    local allObjects = getAllObjects();
    local box = nil;
    local item = nil;
    local name = nil;

    local rotation = {0.00, 0.00, 0.00};

    if flip == false then
        rotation = {0.00, 0.00, 180.00};
    end

    for key, val in ipairs( allObjects ) do
        if val.tag == "Bag" then
            if val.getName() == boxName then
