    end
end

function SetupAdd( boxName, bagName, placeAtPosition, bagPosition, bagRotation, flip )
    if flip == nil then
        flip = true;
    end

    local allObjects = getAllObjects();
    local box = nil;
    local bag = nil;
    local deck = nil;
    local token = nil;

    for key, val in ipairs( allObjects ) do
        if val.tag == "Bag" then
            if val.getName() == boxName then
                box = val;
            elseif val.getName() == bagName then
                bag = val;
            end
        elseif val.tag == "Deck" then
            if val.getName() == bagName then
                deck = val;
            end
        elseif val.hasTag("Token") then
            if val.getName() == bagName then
                token = val;
            end
        end
    end

    if deck ~= nil then
        deck.setPosition( placeAtPosition );
    elseif token ~= nil then
        token.setPosition( placeAtPosition );
    elseif bag ~= nil then
        SetupExtractDeckFromBag( bag, placeAtPosition, flip );
    elseif box ~= nil then
        SetupExtractBagFromBox( box, bagName, placeAtPosition, bagPosition, bagRotation, flip );
    end
end

function split(data)
    pString = data[1]
    pPattern = data[2]
    local Table = {}
    local fpat = "(.-)" .. pPattern
    local last_end = 1
    local s, e, cap = pString:find(fpat, 1)
    while s do
        if s ~= 1 or cap ~= "" then
            table.insert(Table,cap)
        end
        last_end = e+1
        s, e, cap = pString:find(fpat, last_end)
    end
    if last_end <= #pString then
        cap = pString:sub(last_end)
        table.insert(Table, cap)
    end
    return Table
end


